#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool isVowel(char ch){
    return ch=='a'||ch=='e'||ch=='i'||ch=='o'||ch=='u';
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[100005], P[100005];
        scanf("%s", S);
        scanf("%s", P);
        int best = N*2; // upper bound
        for(char c='a'; c<='z'; ++c){
            int cur = 0;
            for(int i=0;i<N;i++){
                char s = (S[i]=='?')?c:S[i];
                char p = (P[i]=='?')?c:P[i];
                if(s==p) continue;
                if(isVowel(s)!=isVowel(p)) cur += 1;
                else cur += 2;
            }
            if(cur<best) best=cur;
        }
        printf("%d\n", best);
    }
    return 0;
}

