import sys

def is_vowel(ch):
    return ch in 'aeiou'

def solve():
    data = sys.stdin.read().splitlines()
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx+=1
        S = data[idx].strip(); idx+=1
        P = data[idx].strip(); idx+=1
        best = n*2
        for c in map(chr, range(ord('a'), ord('z')+1)):
            cur = 0
            for i in range(n):
                s = c if S[i]=='?' else S[i]
                p = c if P[i]=='?' else P[i]
                if s==p:
                    continue
                if is_vowel(s) != is_vowel(p):
                    cur += 1
                else:
                    cur += 2
            if cur < best:
                best = cur
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

